INSERT INTO `recipes` (`id`, `name`, `image_url`, `ingredients`, `secondary_ingredients`, `instructions`, `servings`, `category_id`, `source`, `menu_type`) VALUES
(14, 'เมนูทดสอบ', 'test1.jpg', '[{\"name\": \"วัตถุดิบทดสอบ\", \"amount\": 500, \"unit\": \"กรัม\"}]', NULL, 'ทดสอบ', 1, 6, 'ทดสอบ', '[\"system\"]'),
(15, 'ผัดกะเพราหมูสับ', 'stirfried1.jpg', '[\r\n  {\"name\": \"เนื้อหมูสันคอ\", \"amount\": 400, \"unit\": \"กรัม\"},\r\n  {\"name\": \"กะเพราขาว\", \"amount\": 50, \"unit\": \"กรัม\"},\r\n  {\"name\": \"กระเทียม\", \"amount\": 30, \"unit\": \"กลีบ\"},\r\n  {\"name\": \"พริกจินดา(แดง)\", \"amount\": 12, \"unit\": \"เม็ด\"},\r\n  {\"name\": \"พริกจินดา(แห้ง)\", \"amount\": 6, \"unit\": \"เม็ด\"}\r\n]', '[\r\n  {\"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\"},\r\n  {\"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 1.5, \"unit\": \"ช้อนโต๊ะ\"},\r\n  {\"name\": \"ซอสหอยนางรม\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\"},\r\n  {\"name\": \"ซีอิ๊วดำหวาน\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\"},\r\n  {\"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\"}\r\n]', '[\r\n  \"หั่นหมูสันคอออกเป็นชิ้นๆ แล้วสับหมูให้ละเอียดตามความต้องการ พักไว้\",\r\n  \"โขลกพริกแห้งให้ละเอียด จากนั้นใส่พริกแดงจินดาและกระเทียมลงไปโขลกรวมกัน (หรือปั่นแทนได้)\",\r\n  \"ตั้งกระทะให้ร้อน ใส่น้ำมันพืชพอประมาณ ผัดพริกและกระเทียมให้มีกลิ่นหอม\",\r\n  \"ใส่หมูสับลงไปผัดให้กระจายตัวไม่เกาะเป็นก้อน ผัดจนหมูเริ่มสุก\",\r\n  \"ปรุงรสด้วยน้ำมันหอย น้ำปลา ซอสปรุงรส ซีอิ๊วดำหวาน และน้ำตาลทราย เล็กน้อย เร่งไฟผัดให้เข้ากัน\",\r\n  \"ชิมรสชาติ จากนั้นใส่ใบกะเพราลงไปผัดพอเข้ากัน ปิดเตา ตักเสิร์ฟ\"\r\n]', 4, 3, '{\r\n  \"url\": \"https://food.trueid.net/detail/k7DvOYgLXXeP\",\r\n  \"facebook\": \"กินได้อร่อยด้วย\",\r\n  \"youtube\": \"กินได้อร่อยด้วย\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
(16, 'กุ้งทอดเกลือ', 'fry1.jpg', '[\r\n    { \"name\": \"กุ้ง\", \"amount\": 500, \"unit\": \"กรัม\" },\r\n    { \"name\": \"กระเทียม\", \"amount\": 7, \"unit\": \"กลีบ\" }\r\n]', '[\r\n    { \"name\": \"เนยจืด\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n    { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n    { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.35, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"พริกไทย\", \"amount\": 0.5, \"unit\": \"กรัม\" }\r\n]', '[\r\n    \"นำกุ้งมาล้างทำความสะอาด แล้วเปลือก ผ่าหลังเอาเส้นดำออก\",\r\n    \"นำกระเทียมมาสับพอหยาบๆ\",\r\n    \"ตั้งกระทะใส่น้ำมัน รอจนน้ำมันร้อนจัด\",\r\n    \"นำกุ้งลงทอดให้กุ้งสุกประมาณ 60-80% อย่าทอดนานเกินไปจนเนื้อกุ้งกระด้าง\",\r\n    \"นำกุ้งขึ้นมาพักไว้ แล้วเทน้ำมันออกเล็กน้อย\",\r\n    \"เปิดเตา ใส่เนยลงไป ตามด้วยกระเทียมสับ\",\r\n    \"ใส่กุ้งที่พักไว้ลงไปทอดต่อ เร่งไฟแรงแล้วปรุงรสด้วยซอสหอยนางรม เกลือ ซอสปรุงรส น้ำตาลทราย และพริกไทย\",\r\n    \"คลุกเคล้าให้ส่วนผสมเข้ากันดี จากนั้นตักใส่จานพร้อมเสิร์ฟ\"\r\n]', 3, 2, '{\r\n  \"url\": \"https://food.trueid.net/detail/G1bbdMAIYjk1\",\r\n  \"facebook\": \"กินได้อร่อยด้วย\",\r\n  \"youtube\": \"กินได้อร่อยด้วย\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
