(22, 'ราดหน้าหมูเส้นใหญ่', 'onedishmeal3.jpg', '[\r\n    { \"name\": \"เส้นก๋วยเตี๋ยว ใหญ่(เส้นสด)\", \"amount\": 120, \"unit\": \"กรัม\" },\r\n    { \"name\": \"เนื้อหมู\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n    { \"name\": \"ผักคะน้า\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n    { \"name\": \"กระเทียม\", \"amount\": 2, \"unit\": \"กลีบ\" }\r\n]', '[\r\n    { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"ซีอิ๊วขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n    { \"name\": \"แป้งมันสำปะหลัง\", \"amount\": 5, \"unit\": \"กรัม\" }\r\n]', '', 1, 8, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
