(24, 'ไข่ดาว', 'fry2.jpg', '[\r\n    { \"name\": \"ไข่ไก่\", \"amount\": 1, \"unit\": \"ฟอง\" }\r\n]', '[\r\n    { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]', '[\r\n  \"ตอกไข่ใส่ถ้วยเตรียมไว้\",\r\n  \"ตั้งกระทะบนไฟกลาง ใส่น้ำมันพืชเล็กน้อย\",\r\n  \"รอจนน้ำมันร้อนจัดแล้วค่อย ๆ เทไข่ลงกระทะ\",\r\n  \"ทอดจนไข่ขาวสุกกรอบแต่ไข่แดงยังเยิ้ม (หรือตามระดับสุกที่ต้องการ)\",\r\n  \"ตักขึ้นพักบนกระดาษซับน้ำมัน พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 2, '{\"note\": \"สูตรตามบ้านทั่วไป\"}', '[\"general\", \"system\"]'),
(25, 'ข้าวสวย 1 ถ้วย', 'other1.jpg', '[\r\n    { \"name\": \"ข้าวสวย\", \"amount\": 150, \"unit\": \"กรัม\" }\r\n]', '', '[\r\n    \"ตักข้าวสวยหุงสุกในปริมาณ 1 ถ้วย (ประมาณ 150 กรัม) เตรียมพร้อมเสิร์ฟ\",\r\n    \"สามารถใช้ข้าวที่หุงด้วยหม้อหุงข้าว หรือหม้อต้มก็ได้ตามความสะดวก\",\r\n    \"แนะนำให้พักข้าวให้ระอุก่อนเสิร์ฟประมาณ 5 นาที\"\r\n]', 1, 12, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\", \"system\"]'),
