(45, 'หอยลายผัดพริกเผา', 'stirfried6.jpg', '[\r\n  { \"name\": \"หอยลาย\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ใบโหระพา\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำพริกเผา\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 0.8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ล้างหอยลายให้สะอาด หรือแช่น้ำให้หอยคายโคลน จากนั้นลวกในน้ำเดือดประมาณ 30–40 วินาที แล้วแช่ในน้ำเย็นจัด พักให้สะเด็ดน้ำ\",\r\n  \"ตั้งกระทะ ใส่น้ำมันพืชลงไป พอกระทะร้อนให้ใส่กระเทียมสับและพริกขี้หนูสวนลงผัดจนมีกลิ่นหอม\",\r\n  \"ปรุงรสด้วยน้ำตาลทราย น้ำมันหอย ซีอิ๊วขาว น้ำปลา และน้ำพริกเผา ผัดให้ส่วนผสมเข้ากันดี\",\r\n  \"ใส่หอยลายลงผัดจนฝาหอยเปิดและเนื้อสุกดี จากนั้นใส่ใบโหระพา ผัดพอทั่วแล้วปิดไฟ\",\r\n  \"ตักใส่จานพร้อมเสิร์ฟ รับประทานร้อนๆ กับข้าวสวย\"\r\n]\r\n', 2, 3, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/stir-fried-clams-with-roasted-chili-paste\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ gam.sali\"\r\n}', '[\"system\"]'),
(46, 'แคบหมูผัดพริกขิง', 'stirfried7.jpg', '[\r\n  { \"name\": \"แคบหมู\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ถั่วฝักยาว\", \"amount\": 30, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 8, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกจินดา(แห้ง)\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"ขิงแก่\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 8, \"unit\": \"หัว\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ข่า\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 3, \"unit\": \"ราก\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 5, \"unit\": \"ใบ\" },\r\n  { \"name\": \"พริกจินดา(แดง)\", \"amount\": 2, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ใส่พริกแห้ง กระเทียม ข่าหั่นแว่น ตะไคร้ซอย หอมแดง เกลือสมุทร รากผักชี และขิงหั่นแว่นลงในครก โขลกให้ละเอียดเป็นพริกแกง\",\r\n  \"ตั้งกระทะด้วยไฟปานกลาง ใส่น้ำมันพืชลงไป รอจนร้อนแล้วใส่พริกแกงที่โขลกไว้ลงผัดจนเหลืองหอม\",\r\n  \"ปรุงรสด้วยน้ำปลา น้ำตาลปี๊บ และน้ำเปล่าเล็กน้อย คนให้เข้ากัน\",\r\n  \"ใส่แคบหมู ถั่วฝักยาว พริกแดงหั่นเฉียง และใบมะกรูดลงไป ผัดให้เข้ากันจนพอทั่วดี\",\r\n  \"ตักใส่จาน พร้อมเสิร์ฟทันที\"\r\n]\r\n', 3, 3, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/stir-fried-pork-rinds-with-ginger-curry\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ gam.sali\"\r\n}', '[\"system\"]'),
(47, 'ไข่ข้นแฮม', 'stirfried8.jpg', '[\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 3, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"หมูแฮม\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 2, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เนย(เค็ม)\", \"amount\": 14, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 0.2, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"หั่นแฮมเป็นชิ้นพอดีคำ และหั่นต้นหอมซอย เตรียมไว้\",\r\n  \"ตอกไข่ไก่ใส่ชามผสม ปรุงรสด้วยซีอิ๊วขาว แล้วตีให้ไข่เข้ากันดี\",\r\n  \"ตั้งกระทะให้ร้อน ใส่น้ำมันพืชเล็กน้อย แล้วตามด้วยเนยสด\",\r\n  \"ใส่แฮมลงไปผัดพอหอม จากนั้นเทไข่ที่ตีไว้ลงไป ใช้ตะหลิวลากไข่ไปมาจนได้ระดับความสุกที่ต้องการ แล้วปิดเตา\",\r\n  \"ตักไข่ข้นราดลงบนข้าวสวยร้อน โรยต้นหอมซอย และพริกไทยป่น พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 3, '{\r\n  \"url\": \"https://recipe.sgethai.com/recipes/creamy-omelet-with-bacon-on-rice/\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
(48, 'ไก่หวาน', 'stirfried9.jpg', '[\r\n  { \"name\": \"เนื้อสะโพกไก่\", \"amount\": 500, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 10, \"unit\": \"หัว\" }\r\n]\r\n', '[\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วดำหวาน\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 5 , \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"หั่นเนื้อสะโพกไก่เป็นชิ้นพอดีคำ เตรียมไว้\",\r\n  \"ใส่ไก่ลงในชามผสม ตามด้วยซอสหอยนางรม ซีอิ๊วขาว และซีอิ๊วดำ คลุกให้เข้ากันแล้วหมักทิ้งไว้ประมาณ 30 นาที\",\r\n  \"ตั้งกระทะเปิดไฟกลาง ใส่น้ำมันพืช ใส่หอมแดงลงไปผัดจนเหลืองหอม\",\r\n  \"ใส่เนื้อไก่ที่หมักไว้ลงผัดจนเนื้อเริ่มตึงตัว\",\r\n  \"เติมน้ำเปล่าลงไปเล็กน้อย เคี่ยวต่อจนไก่เริ่มสุกนุ่ม\",\r\n  \"ใส่น้ำตาลปี๊บ คนให้ละลาย จากนั้นเคี่ยวต่อให้ซอสข้นเหนียวและไก่สุกทั่วถึง พร้อมเสิร์ฟ\"\r\n]\r\n', 4, 3, '{\r\n  \"url\": \"https://recipe.sgethai.com/recipes/chicken-in-sweet-sauce/\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
