(62, 'ยำไข่ต้มทรงเครื่อง', 'salad2.jpg', '[\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 1, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 1, \"unit\": \"หัว\" },\r\n  { \"name\": \"มะเขือเทศห\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ขึ้นฉ่าย\", \"amount\": 5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แตงกวา\", \"amount\": 30, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 1, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 2, \"unit\": \"เม็ด\" }\r\n]\r\n', NULL, 1, 10, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
(63, 'ยำถั่วพูไข่ต้ม', 'salad3.jpg', '[\r\n  { \"name\": \"ถั่วพู\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 1, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 1, \"unit\": \"หัว\" },\r\n  { \"name\": \"มะพร้าวคั่ว\", \"amount\": 5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กุ้งแห้ง\", \"amount\": 5, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 1, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 2, \"unit\": \"เม็ด\" }\r\n]\r\n', NULL, 1, 10, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
