(65, 'ชาไทยเย็น', 'drink1.jpg', '[\r\n  { \"name\": \"ชาดำ\", \"amount\": 100, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 15, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', NULL, 1, 11, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
