(67, 'กาแฟเย็น', 'drink3.jpg', '[\r\n  { \"name\": \"ผงกาแฟ\", \"amount\": 1, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 20, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', NULL, 1, 11, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
(68, 'โกโก้เย็น', 'drink4.jpg', '[\r\n  { \"name\": \"ผงโกโก้\", \"amount\": 3, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 20, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมสด\", \"amount\": 50, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', NULL, 1, 11, '{\"note\": \"เป็นเมนูสำเร็จรูป\"}', '[\"general\"]'),
(69, 'เบอร์เกอร์ไก่กรอบ', 'fry6.jpg', '[\r\n  { \"name\": \"สะโพกไก่\", \"amount\": 120, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เบคอน\", \"amount\": 44, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เชดดาชีส\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผักกาดหอม\", \"amount\": 10, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือเทศ(ลูกใหญ่)\", \"amount\": 30, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 1.5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผงปาปริก้า\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"แป้งทอดกรอบ\", \"amount\": 60, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มายองเนส\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"หมักสะโพกไก่กับเกลือ พริกไทย และผงปาปริก้า พักไว้ 15–20 นาทีให้เข้าเนื้อ\",\r\n  \"นำไก่ที่หมักแล้วคลุกแป้งทอดกรอบ 1 รอบ ชุบน้ำ แล้วคลุกแป้งอีกครั้ง ขยี้ให้แป้งเป็นเกล็ด\",\r\n  \"ตั้งกระทะไฟกลางค่อนแรง ใส่น้ำมัน รอจนร้อน นำไก่ลงทอดจนเหลืองกรอบ แล้วเร่งไฟแรงสั้น ๆ เพื่อให้กรอบนาน\",\r\n  \"นำเบคอนลงจี่ในกระทะจนกรอบ พักไว้\",\r\n  \"จัดวางเบอร์เกอร์: เริ่มด้วยไก่ทอด ตามด้วยผักกาดหอม มะเขือเทศ มายองเนส เบคอน ชีส และปิดท้ายด้วยไก่ทอดอีกชั้น\"\r\n]\r\n', 2, 2, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/double-crispy-chicken-burger\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(70, 'ไข่เจียวกรอบกุ้ง', 'fry7.jpg', '[\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 3, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"กุ้ง\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 5, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ผงปรุงรส\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตอกไข่ใส่ถ้วย ใส่น้ำปลา ซอสหอยนางรม ผงปรุงรส กุ้งสับ และต้นหอมซอย ตีให้เข้ากัน\",\r\n  \"กรองไข่ให้เหลือแต่ไข่เหลว แยกเครื่องพักไว้\",\r\n  \"ตั้งกระทะไฟกลาง เทน้ำมันพืชลงไป รอจนน้ำมันร้อนจัด\",\r\n  \"เทไข่ผ่านกระชอนลงในกระทะ ตามด้วยเครื่องกุ้ง\",\r\n  \"ทอดจนไข่ฟูกรอบ สีเหลืองทอง ตักขึ้นให้สะเด็ดน้ำมัน\",\r\n  \"จัดใส่จาน เสิร์ฟร้อน ๆ\"\r\n]\r\n', 2, 2, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/crispy-omelette-with-shrimp\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ gam.sali\"\r\n}', '[\"system\"]'),
(71, 'หมูทอด', 'fry8.jpg', '[\r\n  { \"name\": \"สะโพกหมู\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งทอดกรอบ\", \"amount\": 150, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"รสดีรสหมู\", \"amount\": 2.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"แป้งมันสำปะหลัง\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 100, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ผสมรสดี ซีอิ๊วขาว ซอสหอยนางรม แป้งมัน และนมข้นจืดลงในชามผสม\",\r\n  \"ใส่เนื้อหมูลงไป นวดให้เข้ากับเครื่องหมัก ใช้ส้อมจิ้มหมูให้ทั่วแล้วหมักไว้อย่างน้อย 30 นาที\",\r\n  \"ตั้งกระทะใส่น้ำมันให้ร้อน ปรับเป็นไฟกลาง\",\r\n  \"นำหมูที่หมักไว้มาคลุกแป้งทอดกรอบขณะที่ยังชุ่มน้ำหมัก ขยี้แป้งให้เคลือบทั่วชิ้นหมู\",\r\n  \"นำลงทอดในน้ำมันร้อน 30 วินาที จากนั้นลดเป็นไฟกลางอ่อน ทอดจนสุกเหลือง\",\r\n  \"ตักขึ้น พักให้สะเด็ดน้ำมัน แล้วสับเป็นชิ้นพอดีคำ พร้อมจัดเสิร์ฟ\"\r\n]\r\n', 7, 2, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-crispy-fried-pork\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(72, 'ไก่ทอดกระเทียม', 'fry9.jpg', '[\r\n  { \"name\": \"เนื้อไก่\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 25, \"unit\": \"กลีบ\" }\r\n]\r\n', '[\r\n  { \"name\": \"รากผักชี\", \"amount\": 5, \"unit\": \"ราก\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 2.3, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตั้งกระทะไฟปานกลาง ใส่กระเทียมลงเจียวจนเหลืองหอม ตักขึ้นพักไว้\",\r\n  \"โขลกรากผักชี กระเทียม (สำหรับสามเกลอ) และพริกไทยเม็ด เข้าด้วยกันจนละเอียด\",\r\n  \"ตักน้ำมันเจียว 1 ช้อนโต๊ะลงกระทะ ใส่ส่วนผสมสามเกลอลงผัดจนหอม\",\r\n  \"ใส่เนื้อไก่หั่นลงไป ผัดจนเริ่มสุก ปรุงรสด้วยซอสหอยนางรม ซีอิ๊วขาว ซอสปรุงรส และน้ำตาลทราย\",\r\n  \"ผัดจนไก่สุกทั่วดี ตักใส่จาน โรยหน้าด้วยกระเทียมเจียวและผักชี พร้อมเสิร์ฟ\"\r\n]\r\n', 3, 2, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/fired-chicken-with-garlic\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(73, 'แกงเขียวหวาน', 'curry5.jpg', '[\r\n  { \"name\": \"กะทิ\", \"amount\": 800, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"สะโพกไก่\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือเปราะ\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือพวง\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกชี้ฟ้า(แดง)\", \"amount\": 2, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"ใบโหระพา\", \"amount\": 60, \"unit\": \"ใบ\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 3, \"unit\": \"ใบ\" },\r\n  { \"name\": \"พริกแกงเขียวหวาน\", \"amount\": 70, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตั้งกระทะ ใส่กะทิ 200 มิลลิลิตรและพริกแกงเขียวหวาน ผัดให้หอมและกะทิแตกมัน\",\r\n  \"หั่นเนื้อสะโพกไก่เป็นชิ้นพอดีคำ ใส่ลงผัดกับเครื่องแกงจนไก่เริ่มสุก\",\r\n  \"ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ ชิมรสตามชอบ\",\r\n  \"เติมกะทิที่เหลือลงไป ต้มจนเดือด\",\r\n  \"ใส่ใบมะกรูด มะเขือเปราะ และมะเขือพวงลงต้มจนสุก\",\r\n  \"ใส่พริกชี้ฟ้าแดง เขียว และใบโหระพา คนให้เข้ากัน ปิดไฟ พร้อมเสิร์ฟ\"\r\n]\r\n', 6, 1, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/green-curry\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]'),
(74, 'พะแนงหมู', 'curry6.jpg', '[\r\n  { \"name\": \"กะทิ\", \"amount\": 600, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"เนื้อหมูสันคอ\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือพวง\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ใบโหระพา\", \"amount\": 120, \"unit\": \"ใบ\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 4, \"unit\": \"ใบ\" },\r\n  { \"name\": \"พริกแกงพะแนง\", \"amount\": 30, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1.5, \"unit\": \"ช้อนโต๊ะ\" },  \r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"หั่นสันคอหมูเป็นชิ้นขนาดพอดีคำ พักไว้\",\r\n  \"ตั้งกระทะ ใส่น้ำมันพืชลงไป ใส่พริกแกงพะแนงลงผัดจนหอมและเริ่มสุก\",\r\n  \"เติมกะทิส่วนหนึ่งลงไป เคี่ยวให้แตกมัน\",\r\n  \"ใส่หมูลงไป ผัดจนสุกดี ปรุงรสด้วยน้ำปลาและน้ำตาลปี๊บ\",\r\n  \"เติมกะทิที่เหลือ จากนั้นใส่มะเขือพวง ใบโหระพา และใบมะกรูดลงไป\",\r\n  \"ตักใส่ถ้วย โรยด้วยพริกชี้ฟ้าและใบมะกรูดซอย พร้อมเสิร์ฟ\"\r\n]\r\n', 4, 1, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/panang-curry-with-pork\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]'),
(75, 'แกงมัสมั่นไก่', 'curry7.jpg', '[\r\n  { \"name\": \"น่องไก่\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มันฝรั่ง\", \"amount\": 500, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมหัวใหญ่\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หัวกะทิ\", \"amount\": 480, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"หางกะทิ\", \"amount\": 720, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"พริกแกงมัสมั่น\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เมล็ดมะม่วงหิมพานต์(คั่ว)\", \"amount\": 200, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลมะพร้าว\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"กรัม\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมะขามเปียก\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตั้งหม้อให้ร้อน ใส่หัวกะทิลงไปเคี่ยวจนเดือด\",\r\n  \"ใส่พริกแกงมัสมั่นลงไป เคี่ยวต่อจนกะทิแตกมัน\",\r\n  \"ใส่หอมใหญ่หั่นลงไปผัด ตามด้วยน่องไก่ คลุกให้เข้ากับเครื่องแกง\",\r\n  \"ใส่เม็ดมะม่วงหิมพานต์และมันฝรั่งลงไปผัดให้เคลือบซอส\",\r\n  \"เติมหางกะทิลงไป เคี่ยวต่อด้วยไฟอ่อน 45–60 นาที จนไก่นุ่มและมันฝรั่งสุก\",\r\n  \"ชิมรสและปรุงด้วยน้ำตาลมะพร้าว น้ำปลา และน้ำมะขามเปียกตามชอบ พร้อมเสิร์ฟ\"\r\n]\r\n', 5, 1, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/chicken-mus-sa-man-curry\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]'),
(76, 'แกงเทโพ', 'curry8.jpg', '[\r\n  { \"name\": \"หมูสามชั้น\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กะทิ\", \"amount\": 1000, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"ผักบุ้งไทย(ขาว)\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกแกงแดง\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 5, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมะขามเปียก\", \"amount\": 5, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตั้งหม้อ ใส่หมูสามชั้นลงผัดด้วยไฟกลางจนหมูสุกเหลืองและมีน้ำมันออกมา\",\r\n  \"ใส่พริกแกงแดงลงผัดในน้ำมันหมูจนหอม\",\r\n  \"ทยอยเติมกะทิลงไปทีละส่วน เคี่ยวให้เดือด\",\r\n  \"ฉีกใบมะกรูดใส่ และใส่ผักบุ้งไทยลงไป กดให้จมน้ำแกง\",\r\n  \"ใส่หมูสามชั้นที่ผัดไว้กลับลงหม้อ\",\r\n  \"ปรุงรสด้วยน้ำปลา น้ำตาลปี๊บ และน้ำมะขามเปียก ชิมรสตามชอบ\",\r\n  \"เคี่ยวจนผักบุ้งนุ่ม และน้ำแกงมีความเข้มข้น พร้อมจัดเสิร์ฟ\"\r\n]\r\n', 4, 1, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/pork-curry-with-morning-glory\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ Tanthai Partikornwong\"\r\n}', '[\"system\"]'),
(77, 'แกงส้มผักรวมกุ้งสด', 'curry9.jpg', '[\r\n  { \"name\": \"กุ้ง\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แครอท\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ถั่วฝักยาว\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ดอกกะหล่ำ\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ข้าวโพดอ่อน\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หัวไชเท้า(ดิบ)\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกแกงส้ม\", \"amount\": 45, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำมะขามเปียก\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"หั่นผักทั้งหมดเป็นชิ้นพอดีคำ เช่น ดอกกะหล่ำเป็นดอกเล็ก แครอทและหัวไชเท้าหั่นแว่นหรือตัดแต่งเป็นรูปดอกไม้ ถั่วฝักยาวหั่นท่อน\",\r\n  \"ตั้งหม้อน้ำสะอาดให้เดือด ใส่พริกแกงส้มลงไปคนให้ละลายดี\",\r\n  \"ทยอยใส่ผักลงหม้อตามลำดับความแข็ง เช่น หัวไชเท้า แครอท ดอกกะหล่ำ ข้าวโพดอ่อน ถั่วฝักยาว\",\r\n  \"ปรุงรสด้วยน้ำตาลปี๊บ น้ำปลา และน้ำมะขามเปียก คนให้เข้ากัน ชิมรสเปรี้ยว เค็ม หวานตามชอบ\",\r\n  \"เมื่อผักสุกดี ใส่กุ้งลงไป ต้มจนกุ้งสุกเนื้อเด้ง ตักเสิร์ฟร้อน ๆ\"\r\n]\r\n', 2, 1, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-sour-soup-with-shrimp-and-mixed-vegetables\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]');
INSERT INTO `recipes` (`id`, `name`, `image_url`, `ingredients`, `secondary_ingredients`, `instructions`, `servings`, `category_id`, `source`, `menu_type`) VALUES
(78, 'ข้าวเหนียวมะม่วง', 'dessert5.jpg', '[\r\n  { \"name\": \"ข้าวเหนียวเขี้ยวงู\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กะทิ\", \"amount\": 1250, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"มะม่วงน้ำดอกไม้\", \"amount\": 200, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 32, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 7.5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งข้าวเจ้า\", \"amount\": 5, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"ซาวข้าวเหนียวเขี้ยวงู และแช่ทิ้งไว้จนครบสามชั่วโมง\",\r\n  \"ตั้งหม้อใส่น้ำสำหรับนึ่ง จากนั้นนำผ้าขาวบางมาปูในซึ้ง ตักข้าวเหนียวที่ซาวไว้ใส่ลงไปโดยเว้นตรงกลางเป็นวงกลม แล้วปิดผ้าขาวบางห่อข้าวเหนียวเอาไว้ นึ่งประมาณ 20 นาที\",\r\n  \"พอครบ 20 นาที ใช้ทัพพีกลับข้าวเหนียวเพื่อให้สุกทั่วถึง แล้วนึ่งต่ออีก 10 นาที\",\r\n  \"ผสมน้ำกะทิ อัมพวา กะทิ 100% กับน้ำตาลทราย และเกลือป่น ตั้งไฟอ่อน ๆ เคี่ยวจนน้ำตาลละลายหมด\",\r\n  \"นำข้าวเหนียวที่นึ่งสุกแล้วใส่ชาม เทน้ำกะทิลงไป คนให้เข้ากัน แล้วปิดผ้าขาวบางพักไว้ 30 นาที เพื่อให้ข้าวเหนียวดูดน้ำกะทิ\",\r\n  \"ตั้งไฟอ่อน ๆ ผสมกะทิ อัมพวา กะทิ 100% กับเกลือ และแป้งข้าวเจ้า คนเรื่อย ๆ จนกะทิข้นแล้วยกลงพักไว้\",\r\n  \"ปอกมะม่วงสุกจัดใส่จาน เสิร์ฟพร้อมข้าวเหนียวมูน และราดด้วยน้ำราดกะทิ\"\r\n]\r\n', 5, 4, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/mango-sticky-rice\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]'),
(79, 'กล้วยบวชชี', 'dessert6.jpg', '[\r\n  { \"name\": \"หัวกะทิ\", \"amount\": 1000, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"กล้วยน้ำว้า\", \"amount\": 1000, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 6, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ใบเตย\", \"amount\": 5, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  \"ปอกกล้วย หั่นชิ้นตามชอบ แล้วล้างในน้ำเปล่าผสมเกลือเพื่อไม่ให้กล้วยดำ\",\r\n  \"นำกล้วยไปต้มให้น้ำเดือด 1 รอบเพื่อล้างยางกล้วย\",\r\n  \"ใส่หัวกะทิครึ่งหนึ่งลงในหม้อ ตั้งไฟปานกลางค่อนอ่อนจนร้อน\",\r\n  \"ใส่มัดใบเตย กล้วยต้ม น้ำตาลปี๊บ และเกลือ คนให้เข้ากัน\",\r\n  \"ตั้งให้เดือดและคนเรื่อย ๆ จนน้ำตาลละลายหมด แล้วเติมกะทิส่วนที่เหลือ\",\r\n  \"ต้มต่อเล็กน้อยให้กะทิเข้าเนื้อกล้วย ระวังอย่าให้กล้วยเละ\",\r\n  \"ตักใส่ถ้วยจัดเสิร์ฟ\"\r\n]\r\n', 5, 4, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/kluay-buad-chee\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กิน&GO\"\r\n}', '[\"system\"]'),
(80, 'ฟักทองแกงบวด', 'dessert7.jpg', '[\r\n  { \"name\": \"ฟักทอง\", \"amount\": 500, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หัวกะทิ\", \"amount\": 200, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"หางกะทิ\", \"amount\": 250, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลมะพร้าว\", \"amount\": 80, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ใบเตย\", \"amount\": 5, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  \"ผสมปูนแดงกับน้ำ ทิ้งไว้ให้ตกตะกอน แล้วนำเฉพาะน้ำใส ๆ มาใช้แช่ฟักทองเป็นเวลา 1 ชั่วโมง\",\r\n  \"เทน้ำปูนใสออก แล้วล้างฟักทองด้วยน้ำสะอาดอีก 2 ครั้ง\",\r\n  \"ใส่หางกะทิ น้ำตาลมะพร้าว เกลือ และใบเตยลงในหม้อ ตั้งไฟกลางจนส่วนผสมละลายและเดือด\",\r\n  \"ใส่ฟักทองลงไปต้มในน้ำกะทิ\",\r\n  \"เมื่อกะทิเดือดอีกครั้ง ใส่หัวกะทิลงไป ลดไฟลงเล็กน้อย และต้มจนฟักทองสุก\",\r\n  \"ปิดเตาเมื่อฟักทองสุกดี แล้วตักเสิร์ฟในถ้วย\"\r\n]\r\n', 4, 4, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/pumpkin-in-sweet-coconut-milk\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ แมวเหมียวโมจิ\"\r\n}', '[\"system\"]'),
(81, 'ขนมถ้วยน้ำตาลแดง', 'dessert8.jpg', '[\r\n  { \"name\": \"แป้งข้าวเจ้า\", \"amount\": 240, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งท้าวยายม่อม\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"หัวกะทิ\", \"amount\": 400, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลมะพร้าว\", \"amount\": 400, \"unit\": \"กรัม\" },\r\n  { \"name\": \"น้ำตาลทราย\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  \"ผสมแป้งข้าวเจ้า แป้งท้าวยายม่อม และน้ำให้เข้ากัน\",\r\n  \"ใส่น้ำตาลมะพร้าวลงไปคนจนละลายดี แล้วกรองด้วยกระชอนหนึ่งครั้ง\",\r\n  \"ผสมหัวกะทิ แป้งข้าวเจ้า น้ำตาลทราย และเกลือป่นให้เข้ากัน เตรียมไว้เป็นหน้ากะทิ\",\r\n  \"ตั้งซึ้งให้เดือด ใส่ถ้วยตะไลลงไปให้ร้อน\",\r\n  \"เทแป้งส่วนตัวขนมลงในถ้วยตะไลประมาณครึ่งถ้วย ปิดฝานึ่ง 15 นาที\",\r\n  \"เปิดฝา ใส่ส่วนผสมหน้ากะทิลงไปในถ้วยให้เหลือขอบเล็กน้อย แล้วปิดฝานึ่งต่ออีก 10 นาทีด้วยไฟแรง\",\r\n  \"ตักขนมถ้วยใส่จานพร้อมเสิร์ฟ\"\r\n]\r\n', 5, 4, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-steamed-coconut-milk-pudding\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(82, 'ฝอยทอง', 'dessert9.jpg', '[\r\n  { \"name\": \"ไข่เป็ด(เฉพาะไข่แดง)\", \"amount\": 160, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่(เฉพาะไข่แดง)\", \"amount\": 136, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 42, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ต้มน้ำตาลทรายกับน้ำจนละลายเป็นน้ำเชื่อมใส โดยไม่ต้องคน แล้วพักให้เย็น\",\r\n  \"แยกเฉพาะไข่แดงของไข่ไก่และไข่เป็ด ผสมให้เข้ากันแล้วกรอง\",\r\n  \"นำน้ำค้างไข่ (ไข่ขาวส่วนที่เหลืองค้างในเปลือก) ผสมลงไป แล้วลองยกขึ้นให้หยดเป็นสายไหลต่อเนื่อง\",\r\n  \"ตั้งกระทะ ใส่น้ำตาลทราย น้ำลอยดอกมะลิ และกลิ่นมะลิ ต้มจนน้ำเชื่อมเข้มข้นเดือด แล้วลดไฟลง\",\r\n  \"นำไข่ใส่ลงในกรวยใบตอง แล้วหยอดวนในกระทะประมาณ 30–40 รอบ\",\r\n  \"ใช้ไม้ปลายแหลมช้อนฝอยทองขึ้น แล้วล้างผ่านน้ำเชื่อมใส และจัดทรงตามต้องการ\"\r\n]\r\n', 5, 4, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/foi-thong\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ กินทั้งวัน\"\r\n}', '[\"system\"]'),
(83, 'ต้มยำกุ้งน้ำใส', 'boiled5.jpg', '[\r\n  { \"name\": \"กุ้ง\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เห็ดฟาง\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"ข่า\", \"amount\": 10, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 5, \"unit\": \"ใบ\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 3, \"unit\": \"หัว\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 5, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำมะนาว\", \"amount\": 1.5, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 2.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ผักชีฝรั่ง\", \"amount\": 10, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"ตั้งหม้อต้มน้ำจนเดือด ใส่กุ้งลงไปลวกพอสุกแล้วตักขึ้นพักไว้\",\r\n  \"ใส่ตะไคร้ ข่า หอมแดง พริก เห็ด และใบมะกรูดลงในหม้อเดือด ต้มจนมีกลิ่นหอมแล้วปิดไฟ\",\r\n  \"ปรุงรสด้วยน้ำปลาและน้ำมะนาว ชิมรสตามชอบ\",\r\n  \"ใส่กุ้งลงในถ้วย เสิร์ฟด้วยน้ำซุปต้มยำ และโรยหน้าด้วยผักชีฝรั่ง\"\r\n]\r\n', 3, 5, '{\r\n  \"url\": \"https://cooking.kapook.com/view279753.html\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
(84, 'ต้มข่าไก่', 'boiled6.jpg', '[\r\n  { \"name\": \"สะโพกไก่\", \"amount\": 400, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เห็ดฟาง\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หัวกะทิ\", \"amount\": 300, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"หางกะทิ\", \"amount\": 500, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"ข่าอ่อน\", \"amount\": 12, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 3, \"unit\": \"ต้น\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 6, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกจินดา(แดง)\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 1, \"unit\": \"ผล\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  \"หั่นสะโพกไก่เป็นชิ้นขนาดพอดีคำ\",\r\n  \"ตั้งหม้อบนไฟแรง ใส่หัวกะทิลงไปต้มจนเดือด\",\r\n  \"ใส่ตะไคร้ ข่าอ่อน ใบมะกรูด และเกลือ ลงในหม้อ\",\r\n  \"รอให้เดือดแล้วใส่เนื้อไก่ลงไปต้มจนสุก\",\r\n  \"ปรุงรสด้วยน้ำปลา พริก และบีบมะนาวเล็กน้อยตามชอบ\",\r\n  \"ตักเสิร์ฟใส่ถ้วย รับประทานกับข้าวสวยร้อน ๆ\"\r\n]\r\n', 4, 5, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/tom-khai-gai\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ที่ชื่อ ปากน้ำเมี่ยน\"\r\n}', '[\"system\"]'),
(85, 'ต้มแซ่บกระดูกอ่อน', 'boiled7.jpg', '[\r\n  { \"name\": \"กระดูกหมูอ่อน\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ข่า\", \"amount\": 2, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 5, \"unit\": \"ใบ\" },\r\n  { \"name\": \"ผงชูรส\", \"amount\": 3, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ข้าวคั่ว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 3, \"unit\": \"ผล\" }\r\n]\r\n', '[\r\n  \"เติมน้ำลงหม้อแล้วตั้งไฟให้เดือด จากนั้นใส่ผงปรุงรสและเกลือป่น\",\r\n  \"เมื่อน้ำเดือดจัด ใส่กระดูกหมูอ่อนลงไปแล้วช้อนฟองขาวออกให้หมด\",\r\n  \"ลดไฟลง เคี่ยวกระดูกหมูจนนุ่ม ใส่ข่า ตะไคร้ และใบมะกรูดลงต้มต่อจนหอม\",\r\n  \"ใส่น้ำปลา พริกขี้หนู ข้าวคั่ว และพริกป่นลงไป แล้วปิดไฟ\",\r\n  \"เติมน้ำมะนาวลงไป โรยต้นหอมซอยและผักชีฝรั่งซอย\",\r\n  \"ตักใส่ถ้วย เสิร์ฟคู่กับข้าวเหนียว\"\r\n]\r\n', 4, 5, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/hot-and-spicy-soup-with-pork-ribs\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ จิ๋วหิวโซ\"\r\n}', '[\"system\"]'),
(86, 'ต้นจืดเต้าหู้หมูสับ', 'boiled8.jpg', '[\r\n  { \"name\": \"เนื้อหมู\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แครอท\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผักกาดขาว\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เต้าหู้ไข่\", \"amount\": 240, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 2, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 1, \"unit\": \"กรัม\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 2, \"unit\": \"ราก\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 6, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ขึ้นฉ่าย\", \"amount\": 7, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"นำหมูสับผสมกับพริกไทย กระเทียม และรากผักชีที่โขลกไว้ นวดให้เข้ากัน แล้วปั้นเป็นก้อนพอคำ พักไว้\",\r\n  \"เติมน้ำเปล่าลงหม้อต้มจนเดือด ใส่หมูสับปั้นก้อนลงไป ต้มจนสุก แล้วใส่แครอทลงไป ต้มต่อจนแครอทเริ่มสุก\",\r\n  \"ปรุงรสด้วยซอสปรุงอาหารแม็กกี้ สูตรผัดกลมกล่อม และซอสหอยนางรมแม็กกี้ คนพอเข้ากัน\",\r\n  \"ใส่เต้าหู้ไข่ลงไป พอเดือดแล้วใส่ขึ้นฉ่าย ต้นหอม และกระเทียมเจียว จากนั้นปิดไฟและจัดเสิร์ฟ\"\r\n]\r\n', 3, 5, '{\r\n  \"url\": \"https://www.maggi.co.th/recipes/clear-soup-vegetables-meatballs\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
(87, 'ไก่ต้มขมิ้น', 'boiled9.jpg', '[\r\n  { \"name\": \"สะโพกไก่\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ขมิ้นชัน\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 10, \"unit\": \"หัว\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 2, \"unit\": \"ใบ\" },\r\n  { \"name\": \"ข่า\", \"amount\": 10, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เกลือป่น\", \"amount\": 3, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 2, \"unit\": \"ราก\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" }\r\n]\r\n', '[\r\n  \"ตั้งน้ำให้เดือดจัด แล้วใส่สมุนไพรที่บุบไว้ลงไป เช่น ข่า ตะไคร้ ใบมะกรูด หอมแดง กระเทียม และขมิ้นชัน\",\r\n  \"ต้มจนมีกลิ่นหอมของสมุนไพร\",\r\n  \"ใส่เนื้อไก่ลงไป แล้วลดไฟลงให้น้ำซุปใส\",\r\n  \"ปรุงรสด้วยเกลือและน้ำปลา\",\r\n  \"คอยช้อนฟองออกเพื่อให้น้ำใส และเคี่ยวต่อจนเนื้อไก่เปื่อยนุ่ม\",\r\n  \"ตักเสิร์ฟร้อน ๆ พร้อมน้ำซุปหอมสมุนไพร\"\r\n]\r\n', 4, 5, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/chicken-stew-with-turmeric\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ กินทั้งวัน\"\r\n}', '[\"system\"]'),
(88, 'ไก่ย่างตะไคร้', 'grill5.jpg', '[\r\n  { \"name\": \"เนื้อไก่\", \"amount\": 1200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 1, \"unit\": \"ราก\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 4, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกไทยดำ\", \"amount\": 2, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.25, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"โขลกตะไคร้ รากผักชี กระเทียม และพริกไทยดำให้ละเอียด\",\r\n  \"ผสมเกลือป่น ซอสปรุงรสฝาเขียว ซอสหอยนางรม และน้ำตาลทรายขาวเข้ากับเครื่องที่โขลกไว้\",\r\n  \"นำส่วนผสมที่ได้มาทาให้ทั่วตัวไก่ แล้วหมักทิ้งไว้ประมาณ 30 นาที\",\r\n  \"นำไก่ที่หมักแล้วไปย่างบนเตาด้วยไฟปานกลางจนสุกทั่วทั้งตัว\"\r\n]\r\n', 3, 6, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/grilled-lemongrass-chicken-with-caramel-spicy-sauce\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ หลุมดำผู้ดูดกลืน\"\r\n}', '[\"system\"]'),
(89, 'คอหมูย่าง', 'grill6.jpg', '[\r\n  { \"name\": \"เนื้อหมูสันคอ\", \"amount\": 500, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 2, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำผึ้ง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 60, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 2, \"unit\": \"ราก\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 2, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ใช้ส้อมจิ้มเนื้อคอหมูให้ทั่วเพื่อให้นุ่มและซึมซับเครื่องหมักได้ดี\",\r\n  \"โขลกพริกไทยเม็ด กระเทียม และรากผักชีให้ละเอียด\",\r\n  \"ผสมพริกไทย กระเทียม รากผักชี เกลือ น้ำผึ้ง ซีอิ๊วขาว น้ำมันหอย และนมข้นจืดลงในชามผสม\",\r\n  \"นำเนื้อคอหมูลงคลุกเคล้าให้เข้ากับเครื่องหมัก หมักไว้อย่างน้อย 30 นาที\",\r\n  \"ตั้งกระทะด้วยไฟกลางค่อนไปทางอ่อน นำหมูที่หมักแล้วมาย่างจนสุกทั่วทั้งชิ้น\",\r\n  \"นำหมูย่างที่สุกแล้วมาหั่นเป็นชิ้นบางพอดีคำ\",\r\n  \"จัดใส่จานเสิร์ฟ พร้อมตกแต่งด้วยผักกาดหอม แตงกวา และมะเขือเทศ เสิร์ฟคู่กับน้ำจิ้มแจ่ว\"\r\n]\r\n', 3, 6, '{\r\n  \"url\": \"https://www.wongnai.com/mali/recipes/charcoal-boiled-pork-neck\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ จิ๋วหิวโซ\"\r\n}', '[\"system\"]'),
(90, 'น้ำตกหมู', 'grill7.jpg', '[\r\n  { \"name\": \"เนื้อสันคอหมู\", \"amount\": 400, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผักชีฝรั่ง\", \"amount\": 5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 3, \"unit\": \"หัว\" },\r\n  { \"name\": \"ใบสะระแหน่\", \"amount\": 10, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกป่น\", \"amount\": 3, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ข้าวคั่ว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 2, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1.5, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"STEP 1: หมักหมู – หั่นสันคอหมูเป็นชิ้น แล้วหมักกับซอสหอยนางรม คลุกเคล้าให้เข้ากัน หมักทิ้งไว้ประมาณ 15 นาที\",\r\n  \"STEP 2: ย่างหมู – ย่างหมูหมักบนกระทะด้วยไฟแรงจนสุกทั้งสองด้าน ด้านในยังไม่ต้องสุกมาก แล้วนำมาหั่นเป็นชิ้นพอดีคำ\",\r\n  \"STEP 3: ปรุงรส – ใส่หมูย่างลงในหม้อตั้งไฟ เติมน้ำเปล่าต้มสุก รอให้เดือด ปรุงรสด้วยน้ำตาลปี๊บและน้ำปลา คลุกให้เข้ากัน\",\r\n  \"ใส่หอมแดงซอย ผักชีฝรั่งซอย ต้นหอมซอย และพริกป่นลงไป แล้วปรุงรสด้วยน้ำมะนาว\",\r\n  \"เติมข้าวคั่ว คลุกให้เข้ากันดี แล้วใส่ใบสะระแหน่ลงไปคนให้ทั่ว ปิดไฟ พร้อมเสิร์ฟ\"\r\n]\r\n', 2, 6, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/slide-grilled-pork-salad\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ Healthy_onair\"\r\n}', '[\"system\"]'),
(91, 'ปลาหมึกย่าง', 'grill8.jpg', '[\r\n  { \"name\": \"หมึกกระดอง\", \"amount\": 1200, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"ซีอิ๊วดำหวาน\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ผงขมิ้น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  \"ล้างปลาหมึกด้วยน้ำเกลือ (เกลือ 2 กำมือต่อน้ำ 1 กิโลกรัม) และล้างออกด้วยน้ำสะอาดจนฟองน้อยลง\",\r\n  \"แช่ปลาหมึกในน้ำปูนใสประมาณ 15 นาทีเพื่อให้เนื้อกรอบ แล้วล้างออกอีกครั้ง\",\r\n  \"หมักปลาหมึกด้วยน้ำผสมผงขมิ้นและซีอิ๊วดำ ทิ้งไว้ 15 นาที\",\r\n  \"โขลกรากผักชี กระเทียม และพริกแดงจินดาให้ละเอียด\",\r\n  \"ปรุงน้ำจิ้มซีฟู้ดด้วยเกลือ น้ำตาลปี๊บ น้ำปลา น้ำมะนาว และน้ำต้มสุก ผสมให้เข้ากัน\",\r\n  \"ย่างปลาหมึกด้วยไฟอ่อนจนสุก (ใช้เตาถ่านจะได้รสชาติดีกว่า)\",\r\n  \"หั่นปลาหมึกย่างเป็นชิ้นพอดีคำ จัดเสิร์ฟพร้อมน้ำจิ้มซีฟู้ด\"\r\n]\r\n', 4, 6, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/grilled-squid-with-spicy-sauce\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ Healthy_onair\"\r\n}', '[\"system\"]'),
(92, 'แหนมย่าง', 'grill9.jpg', '[\r\n  { \"name\": \"เนื้อหมู\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หนังหมู\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ข้าวเหนียว(นึ่ง)\", \"amount\": 200, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เกลือป่น\", \"amount\": 6, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 45, \"unit\": \"กลีบ\" }\r\n]\r\n', '[\r\n  \"สับเนื้อหมูติดมันให้ละเอียด\",\r\n  \"โขลกเกลือเม็ดให้ละเอียด\",\r\n  \"โขลกกระเทียมไทยให้ละเอียด\",\r\n  \"ผสมหมูสับกับเกลือและกระเทียมที่โขลกไว้\",\r\n  \"ใส่หนังหมูและข้าวเหนียวลงไป คลุกเคล้าให้เข้ากัน\",\r\n  \"ตักส่วนผสมใส่ถุงแกงแล้วเกลี่ยให้แน่นเป็นทรงกระบอก มัดหัวและท้ายด้วยหนังยาง\",\r\n  \"หมักแหนมที่อุณหภูมิห้องเป็นเวลา 3 วัน\",\r\n  \"นำแหนมหมักมาเสียบไม้\",\r\n  \"ย่างแหนมด้วยไฟอ่อนจนสุก (หากไม่มีน้ำหยดออกแสดงว่าสุกแล้ว)\",\r\n  \"จัดใส่จานเสิร์ฟ พร้อมเครื่องเคียง เช่น ขิงซอย พริกขี้หนู กะหล่ำปลี แตงกวา และผักชี\"\r\n]\r\n', 5, 6, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/grilled-sour-pork\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ gam.sali\"\r\n}', '[\"system\"]'),
(93, 'ไก่นึงมะนาว', 'steam5.jpg', '[\r\n  { \"name\": \"เนื้อไก่สันใน\", \"amount\": 500, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 12, \"unit\": \"กลีบ\" },           \r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 20, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 0.75, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ขึ้นฉ่าย\", \"amount\": 8, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"ผสมน้ำยำโดยใช้กระเทียมฝาน พริกขี้หนูซอย น้ำตาลทราย น้ำปลา และน้ำมะนาว คนให้เข้ากันดีแล้วพักไว้\",\r\n  \"ตั้งน้ำในหม้อให้เดือด แล้ววางลังถึงไว้ด้านบน\",\r\n  \"นำสันในไก่วางในจานแล้วใส่ในลังถึง นึ่งประมาณ 15 นาทีจนเกือบสุก\",\r\n  \"เมื่อไก่ใกล้สุกแล้ว ราดน้ำยำลงบนไก่ในจาน แล้วนึ่งต่ออีก 5 นาที\",\r\n  \"จัดไก่นึ่งมะนาวใส่จาน ตกแต่งด้วยมะนาว ผักชี และพริกชี้ฟ้าตามชอบ พร้อมเสิร์ฟ\"\r\n]\r\n', 2, 7, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/chicken-steamed-with-thai-spicy-sauce\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ Healthy_onair\"\r\n}', '[\"system\"]'),
(94, 'ขนมจีบหมูเด้ง', 'steam6.jpg', '[\r\n  { \"name\": \"กุ้ง\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เนื้อหมู\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แครอท\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แผ่นเกี๊ยว\", \"amount\": 20, \"unit\": \"แผ่น\" }\r\n]\r\n', '[\r\n  { \"name\": \"รากผักชี\", \"amount\": 2, \"unit\": \"ราก\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 3, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกไทยดำ\", \"amount\": 2, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันงา\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"แป้งข้าวโพด\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"โขลกรากผักชี กระเทียม และพริกไทยให้ละเอียด\",\r\n  \"ผสมกุ้งสับ หมูสับ แครอท ซอสปรุงรส น้ำมันหอย น้ำตาล น้ำมันงา และแป้งข้าวโพด คลุกให้เข้ากันเป็นเนื้อเดียว\",\r\n  \"วางแผ่นเกี๊ยวบนนิ้ว ตักไส้ประมาณ 1 ช้อนโต๊ะใส่ลงไป ใช้นิ้วจัดทรงจีบ แล้วกดให้เป็นรูปทรงขนมจีบ\",\r\n  \"พรมน้ำบนขนมจีบเพื่อให้แป้งนิ่ม แล้วนำไปนึ่งประมาณ 15-20 นาที หรือจนสุก\",\r\n  \"จัดเสิร์ฟ โรยด้วยกระเทียมเจียว เสิร์ฟพร้อมจิ๊กโฉ่ว\"\r\n]\r\n', 3, 7, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/pork-dim-sum\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ กินทั้งวัน\"\r\n}', '[\"system\"]'),
(95, 'หมูยอโฮมเมด', 'steam7.jpg', '[\r\n  { \"name\": \"เนื้อหมู\", \"amount\": 1000, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 6, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผงฟู\", \"amount\": 4.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"แป้งมันสำปะหลัง\", \"amount\": 16, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"นำหมูบดใส่ชามผสม ใส่น้ำมันถั่วเหลือง น้ำปลา น้ำตาลทราย พริกไทย ผงฟู และแป้งมัน คลุกเคล้าให้เข้ากัน\",\r\n  \"นำส่วนผสมที่คลุกแล้วไปใส่เครื่องปั่น ปั่นให้เนื้อเนียนละเอียด แล้วนำไปแช่เย็นสักครู่ (สามารถใส่น้ำแข็งระหว่างปั่นเพื่อให้หมูยอเด้ง)\",\r\n  \"ตัดใบตอง 2 ขนาด (เล็ก: 4-5 นิ้ว / ใหญ่: 12-16 นิ้ว) เตรียมไว้สำหรับห่อ\",\r\n  \"วางใบตองใหญ่ด้านล่างซ้อนด้วยใบตองเล็ก วางหมูบดที่ปั่นไว้ประมาณ 150-180 กรัมลงไป แล้วห่อให้แน่น\",\r\n  \"พับปลายใบตองเข้าหากัน และมัดด้วยหนังยางให้เรียบร้อย\",\r\n  \"นำหมูยอที่ห่อเสร็จแล้วไปนึ่งในหม้อน้ำเดือด ประมาณ 30-40 นาที (ขึ้นกับขนาดชิ้น)\",\r\n  \"เมื่อสุกดีแล้ว ยกขึ้นพัก และพร้อมเสิร์ฟหรือเก็บไว้กินต่อได้\"\r\n]\r\n', 4, 7, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/homemade-vietnamese-ham\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ pimtp__\"\r\n}', '[\"system\"]'),
(96, 'ปลากะพงนึ่งมะนาว', 'steam8.jpg', '[\r\n  { \"name\": \"ปลากะพงขาว\", \"amount\": 750, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 8, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 3, \"unit\": \"ผล\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ล้างปลากะพงให้สะอาด บั้งตัวปลา แล้ววางลงบนจานสำหรับนึ่ง\",\r\n  \"ผสมน้ำยำโดยใช้น้ำซุป น้ำปลา น้ำตาลทราย และน้ำมะนาว คนให้เข้ากัน\",\r\n  \"ราดน้ำยำลงบนตัวปลา นำไปนึ่งในน้ำเดือดประมาณ 20 นาทีจนปลาสุก\",\r\n  \"ตกแต่งด้วยกระเทียมสไลซ์ พริกขี้หนูซอย และขึ้นฉ่ายซอยก่อนเสิร์ฟ\"\r\n]\r\n', 2, 7, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/steamed-seabass-with-lime\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ gam.sali\"\r\n}', '[\"system\"]'),
(97, 'ไข่ตุ๋นหมูเด้ง', 'steam9.jpg', '[\r\n  { \"name\": \"เนื้อหมูสันใน\", \"amount\": 250, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 2, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"แครอท\", \"amount\": 15, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"แป้งมันสำปะหลัง\", \"amount\": 4.5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผงฟู\", \"amount\": 2, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ผงปรุงชูรส\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 1, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  \"นำเนื้อหมูสันใน แป้งมัน ผงฟู ผงปรุงรส และน้ำเย็นจัดใส่ลงในเครื่องปั่น ปั่นจนเนียนละเอียด แล้วพักไว้\",\r\n  \"ตอกไข่ใส่ชาม ใส่ซีอิ๊วขาว ตีให้เข้ากัน แล้วเติมน้ำเปล่าและกรองส่วนผสม พักไว้\",\r\n  \"ตักหมูเด้งใส่ชาม เสียบแครอทบริเวณขอบชาม แล้วเกลี่ยให้ทั่วจนเต็มชาม\",\r\n  \"เทไข่ที่เตรียมไว้ลงในชามหมูเด้ง แล้วยกขึ้นใส่ลังถึง\",\r\n  \"นึ่งด้วยไฟอ่อนประมาณ 20 นาทีจนไข่เซตตัว\",\r\n  \"คว่ำใส่จาน โรยต้นหอม ตกแต่ง พร้อมเสิร์ฟ\"\r\n]\r\n', 4, 7, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/steamed-egg-in-pork-bowl\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(98, 'ข้าวหน้าไก่', 'onedishmeal5.jpg', '[\r\n  { \"name\": \"สะโพกไก่\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เห็ดหอม\", \"amount\": 30, \"unit\": \"กรัม\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 240, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 1.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสหอยนางรม\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันงา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เหล้าจีน\", \"amount\": 15, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 2, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ซีอิ๊วดำ\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 6, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"แป้งข้าวโพด\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ผสมซีอิ๊วขาว ซอสหอยนางรม น้ำมันงา เหล้าจีน นมข้นจืด และสะโพกไก่ในชามผสม คลุกให้เข้ากันแล้วหมักไว้ 20 นาที\",\r\n  \"ตั้งกระทะ ใส่น้ำมันเล็กน้อย ใส่กระเทียมสับผัดจนเหลืองหอม ใส่ไก่ที่หมักไว้ลงผัดให้พอสุก ใส่เห็ดหอมลงผัดต่อแล้วเติมน้ำเปล่าประมาณครึ่งลิตร\",\r\n  \"ตั้งให้เดือด ปรุงรสด้วยซอสปรุงรส น้ำตาล ซีอิ๊วดำ และพริกไทย ตั้งให้เดือดอีกครั้ง แล้วค่อย ๆ เทแป้งข้าวโพดละลายน้ำลงไป คนตลอดจนซอสข้นเหนียวดีแล้วยกขึ้นจากเตา\",\r\n  \"ตักเสิร์ฟพร้อมข้าวสวยและกุนเชียงทอด โรยตกแต่งด้วยผักชี\"\r\n]\r\n', 2, 8, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/marinated-chicken-with-sauce-over-rice\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(99, 'กะเพราไก่สับ', 'onedishmeal6.jpg', '[\r\n  { \"name\": \"เนื้อไก่\", \"amount\": 150, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กะเพราขาว\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 8, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"ข้าวสวย\", \"amount\": 150, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 1, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ตั้งกระทะ ใส่น้ำมัน เปิดไฟกลางจนร้อน ใส่กระเทียมและพริกลงผัดประมาณ 5-10 วินาทีจนหอม\",\r\n  \"ใส่เนื้อไก่สับลงผัดจนสุกดี\",\r\n  \"ปรุงรสด้วยซีอิ๊วขาว น้ำตาล น้ำปลา และเติมน้ำเปล่าหรือน้ำซุปเล็กน้อย\",\r\n  \"ใส่ใบกะเพราลงไปผัดให้เข้ากัน ยกลงจากกระทะ\",\r\n  \"จัดเสิร์ฟราดบนข้าวสวยร้อนๆ พร้อมทาน\"\r\n]\r\n', 1, 8, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/stir-fried-minced-chicken-and-basil-by-big-c\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ Pabair\"\r\n}', '[\"system\"]'),
(100, 'ข้าวผัดปลากระป๋อง', 'onedishmeal7.jpg', '[\r\n  { \"name\": \"ข้าวสวย\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ปลากระป๋อง\", \"amount\": 60, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 3, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 6, \"unit\": \"หัว\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 8, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"รสดีรสหมู\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 5, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  \"ตั้งกระทะใช้ไฟปานกลาง ใส่น้ำมันลงไป พอน้ำมันร้อนใส่กระเทียมและพริกขี้หนู ผัดจนกระเทียมหอมและเหลือง ใส่หอมแดงผัดต่อให้สุกอ่อนตัว\",\r\n  \"ใส่ข้าวสวยลงไปผัดให้เข้ากัน ใส่ปลากระป๋องและน้ำปลากระป๋อง ใช้ตะหลิวยีให้ปลากระป๋องแตกเป็นชิ้นเล็ก ๆ\",\r\n  \"ปรุงรสด้วยเกลือ ผงปรุงรสหมู และน้ำตาล ผัดให้เข้ากันดี\",\r\n  \"ใส่ต้นหอมซอย ผัดอีกครั้งให้เข้ากัน แล้วปิดไฟ\",\r\n  \"ตักข้าวผัดปลากระป๋องใส่จาน โรยผักชี จัดเสิร์ฟพร้อมน้ำปลาพริก\"\r\n]\r\n', 1, 8, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/fried-rice-with-sardines-in-ketchup\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ Foppyfonefone\"\r\n}', '[\"system\"]'),
(101, 'มาม่าผัดไข่', 'onedishmeal8.jpg', '[\r\n  { \"name\": \"เส้นมาม่า\", \"amount\": 1, \"unit\": \"ก้อน\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 1.5, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"กะหล่ำปลี\", \"amount\": 60, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทราย\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันหอย\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันถั่วเหลือง\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ลวกเส้นมาม่าในน้ำเดือดจนเหนียวนุ่ม ตักขึ้นพักให้สะเด็ดน้ำ\",\r\n  \"ตั้งกระทะ ใส่น้ำมัน พอร้อนใส่กระเทียมผัดให้หอม\",\r\n  \"ใส่ไข่ลงไปผัดพอสุก\",\r\n  \"ใส่กะหล่ำปลีลงไปผัดให้สุกตามชอบ\",\r\n  \"ใส่เส้นมาม่าลงไป ปรุงรสด้วยซีอิ๊วขาว น้ำตาล น้ำมันหอย ผัดให้เข้ากัน\",\r\n  \"ตักใส่จาน พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 8, '{\r\n  \"url\": \"https://cooking.kapook.com/view271983.html\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"\"\r\n}', '[\"system\"]'),
(102, 'หอยทอด', 'onedishmeal9.jpg', '[\r\n  { \"name\": \"หอยแมลงภู่\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 1, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"ถั่วงอก\", \"amount\": 200, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"แป้งข้าวเจ้า\", \"amount\": 16, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งท้าวยายม่อม\", \"amount\": 8, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งทอดกรอบ\", \"amount\": 8, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 1, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 0.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 5, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 1, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"น้ำมันรำข้าว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาล\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซีอิ๊วขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ผสมแป้งข้าวเจ้า แป้งทอดกรอบ พริกไทย และเกลือให้เข้ากัน เติมน้ำปูนใสและน้ำโซดาเย็นจัด คนให้แป้งละลายดี ใส่หอยแมลงภู่และต้นหอมซอย คนให้เข้ากันเป็นเนื้อเดียว\",\r\n  \"ตั้งกระทะ ใส่น้ำมัน เปิดไฟกลาง ผัดกระเทียมให้เหลืองเล็กน้อย พอน้ำมันร้อน เทแป้งหอยทอดลงไปให้กระจายทั่วกระทะ\",\r\n  \"เมื่อแป้งเริ่มอยู่ตัว ตอกไข่ไก่ใส่ ใช้ตะหลิวเกลี่ยไข่ให้ทั่ว ทอดจนแป้งเหลืองกรอบแล้วกลับด้านทอดอีกข้าง จากนั้นตักขึ้นพักไว้\",\r\n  \"ในกระทะใบเดิม เทน้ำมันออกให้เหลือเล็กน้อย ผัดกระเทียมจนหอม ใส่ถั่วงอก ซีอิ๊วขาว ซอสปรุงรส และน้ำตาล ผัดจนสุกและเข้ากันดี\",\r\n  \"จัดถั่วงอกผัดใส่จาน วางหอยทอดร้อน ๆ บนถั่วงอก โรยพริกไทย ตกแต่งด้วยผักชี เสิร์ฟพร้อมน้ำจิ้มหอยทอดหรือน้ำจิ้มไก่ตามชอบ\"\r\n]\r\n', 1, 8, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/hoi-tod-pang-krob\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ แพรเพลินพุง\"\r\n}', '[\"system\"]'),
(103, 'ข้าวโพดทอดใส้นม', 'snack5.jpg', '[\r\n  { \"name\": \"ข้าวโพด(ดิบ)\", \"amount\": 120, \"unit\": \"กรัม\" },\r\n  { \"name\": \"นมสด\", \"amount\": 360, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 1, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"เนยจืด\", \"amount\": 20, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"แป้งเทมปุระ\", \"amount\": 16, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งข้าวโพด\", \"amount\": 12, \"unit\": \"กรัม\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ผงปรุงรส\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 60, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"แกะข้าวโพดออกจากซัง ใช้มีดเฉือนเมล็ดออกจากฝัก คลุกเมล็ดข้าวโพดกับแป้งเทมปุระและผงปรุงรส พรมน้ำเย็นจัดเล็กน้อยแล้วพักไว้ในตู้เย็น\",\r\n  \"ผสมนมสด น้ำตาลทราย นมข้นหวาน และแป้งข้าวโพด คนให้เข้ากันดี ตั้งไฟอ่อน คนเรื่อย ๆ จนข้นขึ้น ใส่เนยลงไปคนจนละลาย พักให้เย็นแล้วนำไปแช่ช่องแข็งจนแข็งดี จากนั้นตัดแบ่งเป็นก้อน\",\r\n  \"นำไส้นมที่ตัดแบ่งมาคลุกแป้งเทมปุระ ชุบไข่ จากนั้นใช้เมล็ดข้าวโพดที่เตรียมไว้ปั้นห่อรอบไส้นม\",\r\n  \"ทอดด้วยไฟปานกลางจนสีเหลืองทอง ตักขึ้นพร้อมเสิร์ฟ\"\r\n]\r\n', 2, 9, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/easy-snack-recipes\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ tonhom\"\r\n}', '[\"system\"]'),
(104, 'ลูกชิ้นกุ้งไร้แป้ง', 'snack6.jpg', '[\r\n  { \"name\": \"กุ้งบด\", \"amount\": 1000, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หมูสับ\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กุ้ง\", \"amount\": 300, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 2, \"unit\": \"ฟอง\" }\r\n]\r\n', '[\r\n  { \"name\": \"รากผักชี\", \"amount\": 3, \"unit\": \"ราก\" },\r\n  { \"name\": \"พริกไทย\", \"amount\": 4, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 20, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ซอสปรุงรสฝาเขียว\", \"amount\": 4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันพืช\", \"amount\": 33, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"โขลกกระเทียม พริกไทยเม็ด และรากผักชีให้ละเอียด\",\r\n  \"ใส่กุ้งบดลงในชามผสม ตามด้วยหมูสับ ไข่ไก่ ปรุงรสด้วยสามเกลอ เกลือ น้ำตาลทราย และซอสปรุงรส คนให้เข้ากัน\",\r\n  \"ใส่กุ้งหั่นชิ้นลงไป คนให้เข้ากันอีกครั้ง\",\r\n  \"ปั้นเป็นลูกกลม ๆ ขนาดตามชอบ\",\r\n  \"ทอดลูกชิ้นกุ้งด้วยไฟกลางจนสุกเหลืองกรอบ พร้อมเสิร์ฟ\"\r\n]\r\n', 8, 9, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/easy-snack-recipes\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ tonhom\"\r\n}', '[\"system\"]'),
(105, 'ทอดมันเห็ด', 'snack7.jpg', '[\r\n  { \"name\": \"เห็ดนางฟ้า\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งทอดกรอบ\", \"amount\": 120, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 2, \"unit\": \"ฟอง\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกแกงแดง\", \"amount\": 30, \"unit\": \"กรัม\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 0.8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"ใบมะกรูด\", \"amount\": 4, \"unit\": \"ใบ\" }\r\n]\r\n', '[\r\n  \"ล้างเห็ดนางฟ้าให้สะอาด หั่นเป็นชิ้นเต๋าแล้วพักให้สะเด็ดน้ำ\",\r\n  \"ผสมน้ำพริกแกงเผ็ดกับไข่ไก่ คนให้เข้ากันดี ใส่เห็ดนางฟ้าลงไป ปรุงรสด้วยน้ำปลาและน้ำตาลทราย\",\r\n  \"ใส่แป้งทอดกรอบและใบมะกรูด คนส่วนผสมให้เข้ากันจนมีลักษณะข้น\",\r\n  \"ตั้งกระทะใส่น้ำมันพืชพอร้อน ตักส่วนผสมหยอดลงกระทะให้เป็นชิ้นเท่า ๆ กัน ทอดจนสุกเหลือง\",\r\n  \"ตักขึ้นพักให้สะเด็ดน้ำมัน เสิร์ฟร้อน ๆ พร้อมอาจาด\"\r\n]\r\n', 2, 9, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/easy-snack-recipes\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ tonhom\"\r\n}', '[\"system\"]'),
(106, 'ทุเรียนทอด', 'snack8.jpg', '[\r\n  { \"name\": \"ทุเรียนดิบ\", \"amount\": 550, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"เกลือป่น\", \"amount\": 1.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"น้ำมันปาล์ม\", \"amount\": 33, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ปอกทุเรียนดิบ เอาเมล็ดออก แล้วฝานเนื้อทุเรียนเป็นแผ่นบาง ๆ\",\r\n  \"ตั้งกระทะใส่น้ำมันปาล์ม รอจนร้อน ใส่เนื้อทุเรียนฝานลงทอดจนสุกกรอบ\",\r\n  \"ตักทุเรียนทอดขึ้นพักให้สะเด็ดน้ำมัน\",\r\n  \"โรยเกลือหรือผงปรุงรสตามชอบ คลุกให้เข้ากัน พร้อมเสิร์ฟ\"\r\n]\r\n', 2, 9, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/easy-snack-recipes\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ tonhom\"\r\n}', '[\"system\"]'),
(107, 'กล้วยแขก', 'snack9.jpg', '[\r\n  { \"name\": \"แป้งข้าวเจ้า\", \"amount\": 250, \"unit\": \"กรัม\" },\r\n  { \"name\": \"แป้งข้าวโพด\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"มะพร้าวขูด\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"งาขาว(ดิบ)\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"กล้วยน้ำว้า\", \"amount\": 600, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 8, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"เกลือป่น\", \"amount\": 3, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"ผงฟู\", \"amount\": 4.5, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"นมข้นจืด\", \"amount\": 250, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"น้ำปูนใส\", \"amount\": 70, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"ใบเตย\", \"amount\": 7, \"unit\": \"ใบ\" },\r\n  { \"name\": \"น้ำมันปาล์ม\", \"amount\": 33, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ผสมแป้งข้าวเจ้า แป้งข้าวโพด น้ำตาล เกลือป่น และผงฟูเข้าด้วยกันในชามผสม\",\r\n  \"เติมน้ำปูนใสและนมข้นจืด ใช้ตะกร้อมือคนให้เข้ากันจนเนียน\",\r\n  \"ใส่มะพร้าวขูด งาขาว และใบเตย คนให้เข้ากันเป็นเนื้อเดียว\",\r\n  \"สไลซ์กล้วยน้ำว้าเป็นแผ่นบาง แล้วนำไปคลุกในแป้งที่เตรียมไว้\",\r\n  \"ตั้งกระทะไฟปานกลาง ใส่น้ำมันปาล์มจนร้อน นำกล้วยลงทอดจนเหลืองกรอบ\",\r\n  \"ตักกล้วยแขกขึ้นพักให้สะเด็ดน้ำมัน พร้อมเสิร์ฟ\"\r\n]\r\n', 5, 9, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/easy-snack-recipes\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ tonhom\"\r\n}', '[\"system\"]'),
(108, 'ยำวุ้นเส้นหมูยอ', 'salad5.jpg', '[\r\n  { \"name\": \"วุ้นเส้น\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หมูยอ\", \"amount\": 100, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ขึ้นฉ่าย\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือเทศราชินี\", \"amount\": 50, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมหัวใหญ่\", \"amount\": 50, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกจินดา(แดง)\", \"amount\": 15, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"ถั่วลิสง(ดิบ)\", \"amount\": 20, \"unit\": \"กรัม\" },\r\n  { \"name\": \"น้ำมะนาว\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"แช่วุ้นเส้นในน้ำประมาณ 10 นาที แล้วนำไปลวกให้สุก\",\r\n  \"หั่นหมูยอเป็นแว่น แล้วหั่นครึ่ง เตรียมไว้\",\r\n  \"คั่วถั่วลิสงจนหอม แล้วพักไว้\",\r\n  \"ปรุงน้ำยำด้วยน้ำมะนาว น้ำปลา น้ำตาลทราย และพริกแดงจินดาซอย คนให้ส่วนผสมละลายเข้ากัน\",\r\n  \"ใส่วุ้นเส้นลวกสุก หมูยอ มะเขือเทศเชอร์รี่ และหอมหัวใหญ่ลงในชาม คลุกเคล้าให้เข้ากัน\",\r\n  \"ตักยำวุ้นเส้นใส่จาน โรยหน้าด้วยถั่วลิสงคั่วและขึ้นฉ่าย พร้อมเสิร์ฟ\"\r\n]\r\n', 2, 10, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/glass-noodle-vietnamese-ham-spicy-salad\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ pimtp__\"\r\n}', '[\"system\"]'),
(109, 'กุ้งมะนาว', 'salad6.jpg', '[\r\n  { \"name\": \"กุ้ง\", \"amount\": 500, \"unit\": \"กรัม\" },\r\n  { \"name\": \"รากผักชี\", \"amount\": 3, \"unit\": \"ราก\" },\r\n  { \"name\": \"กระเทียม\", \"amount\": 5, \"unit\": \"กลีบ\" },\r\n  { \"name\": \"พริกจินดา(แดง)\", \"amount\": 7, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"มะนาว\", \"amount\": 2, \"unit\": \"ผล\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1.5, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทราย\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ใส่กระเทียม พริกแดง และรากผักชีลงในครก โขลกให้เข้ากัน\",\r\n  \"ปรุงรสด้วยน้ำปลา น้ำมะนาว และน้ำตาลทราย คนให้เข้ากัน\",\r\n  \"ลวกกุ้งในน้ำเดือดจนสุกดี แล้วตักขึ้นใส่น้ำเย็นเพื่อให้เนื้อกุ้งเด้งกรอบ\",\r\n  \"จัดเสิร์ฟกุ้งลวกพร้อมก้านคะน้าและแครอทลวก ราดด้วยน้ำจิ้มที่โขลกไว้\"\r\n]\r\n', 4, 10, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/boiled-shrimp-with-lime-chili-sauce\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ ซีซ่าร์ไม่ชอบกินกล้วย จะเอาลาบแซ่บๆ\"\r\n}', '[\"system\"]'),
(110, 'ยำปลาทู', 'salad7.jpg', '[\r\n  { \"name\": \"ปลาทู(นึ่ง)\", \"amount\": 360, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"ตะไคร้\", \"amount\": 2, \"unit\": \"ต้น\" },\r\n  { \"name\": \"ผักชีฝรั่ง\", \"amount\": 6, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 3, \"unit\": \"หัว\" },\r\n  { \"name\": \"ขิงอ่อน\", \"amount\": 7, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 3, \"unit\": \"กรัม\" },\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำมะนาว\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลปี๊บ\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"นำปลาทูนึ่งไปย่างบนกระทะจนขึ้นสีทั่ว จากนั้นพักให้เย็นแล้วแกะเป็นชิ้นเล็ก ๆ\",\r\n  \"ผสมน้ำตาลปี๊บ น้ำมะนาว น้ำปลา และพริกขี้หนูแดงในถ้วย คนให้เข้ากันจนน้ำตาลละลาย\",\r\n  \"ใส่เนื้อปลาทูที่แกะไว้พร้อมกับเครื่องสมุนไพรทั้งหมดลงในชามผสม\",\r\n  \"ราดน้ำยำที่เตรียมไว้ลงในชาม แล้วคลุกเคล้าทุกอย่างให้เข้ากัน\",\r\n  \"ตักใส่จานจัดเสิร์ฟ\"\r\n]\r\n', 2, 10, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-mackerel-salad\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ gam.sali\"\r\n}', '[\"system\"]'),
(111, 'ยำไข่ดาวกรอบ', 'salad8.jpg', '[\r\n  { \"name\": \"ไข่ไก่\", \"amount\": 6, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"มะเขือเทศ(ลูกใหญ่)\", \"amount\": 240, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมหัวใหญ่\", \"amount\": 75, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ขึ้นฉ่าย\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n  { \"name\": \"ต้นหอม\", \"amount\": 10, \"unit\": \"กรัม\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 5, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 3, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมะนาว\", \"amount\": 6, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำมันปาล์ม\", \"amount\": 22, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ตั้งกระทะใส่น้ำมัน ใช้ไฟปานกลาง เมื่อน้ำมันร้อนนำไข่ลงทอดจนกรอบทั้งสองด้าน แล้วยกขึ้นพักให้สะเด็ดน้ำมัน\",\r\n  \"ทำน้ำยำโดยผสมน้ำปลา น้ำตาลทราย น้ำมะนาว และพริกขี้หนูลงในชาม คนให้น้ำตาลละลาย\",\r\n  \"ใส่หอมหัวใหญ่ มะเขือเทศ ต้นหอม ขึ้นฉ่าย และไข่ดาวลงคลุกเคล้าให้เข้ากันกับน้ำยำ\",\r\n  \"ตักไข่ดาวใส่จาน ราดน้ำยำที่คลุกไว้ลงไป พร้อมเสิร์ฟ\"\r\n]\r\n', 3, 10, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-mackerel-salad\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ จิ๋วหิวโซ\"\r\n}', '[\"system\"]'),
(112, 'ยำไข่ต้มตาหวาน', 'salad9.jpg', '[\r\n  { \"name\": \"ไข่เป็ด\", \"amount\": 10, \"unit\": \"ฟอง\" },\r\n  { \"name\": \"หมูสับ\", \"amount\": 200, \"unit\": \"กรัม\" },\r\n  { \"name\": \"มะเขือเทศราชินี\", \"amount\": 150, \"unit\": \"กรัม\" },\r\n  { \"name\": \"หอมแดง\", \"amount\": 3, \"unit\": \"หัว\" }\r\n]\r\n', '[\r\n  { \"name\": \"พริกขี้หนู\", \"amount\": 10, \"unit\": \"เม็ด\" },\r\n  { \"name\": \"น้ำมะนาว\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำปลา\", \"amount\": 2, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" }\r\n]\r\n', '[\r\n  \"ใส่ไข่เป็ดในหม้อ เติมน้ำให้ท่วมประมาณ 2/3 ของไข่ ใส่เกลือและน้ำส้มสายชู ต้มด้วยไฟปานกลาง 7 นาที\",\r\n  \"นำไข่เป็ดต้มแช่น้ำเย็นแล้วแกะเปลือกเตรียมไว้\",\r\n  \"ลวกหมูสับให้สุก พักไว้\",\r\n  \"ทำน้ำยำโดยผสมน้ำปลา น้ำมะนาว น้ำตาล พริกขี้หนู หอมแดง มะเขือเทศราชินี และหมูสับ คนให้เข้ากันจนน้ำตาลละลาย\",\r\n  \"จัดเรียงไข่เป็ดบนจาน ราดน้ำยำ โรยผักชี พร้อมเสิร์ฟ\"\r\n]\r\n', 10, 10, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/soft-boiled-duck-egg-with-spicy-dressing\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ gam.sali\"\r\n}', '[\"system\"]'),
(113, 'โกโก้ร้อน', 'drink5.jpg', '[\r\n  { \"name\": \"นมสด\", \"amount\": 100, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"ผงโกโก้\", \"amount\": 2, \"unit\": \"ช้อนชา\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำเปล่า\", \"amount\": 50, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 10, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"อุ่นน้ำเปล่าในไมโครเวฟ 20–30 วินาที\",\r\n  \"ใส่ผงโกโก้ลงในน้ำร้อนแล้วคนให้เข้ากัน\",\r\n  \"เติมนมข้นหวานลงไปแล้วคนจนเข้ากันดี\",\r\n  \"เติมนมสดลงในแก้ว คนให้เข้ากัน\",\r\n  \"อุ่นส่วนผสมในไมโครเวฟอีกครั้ง 20–30 วินาที\",\r\n  \"เสิร์ฟโกโก้ร้อนพร้อมดื่ม\"\r\n]\r\n', 1, 11, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/cocoa-recipe\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ พริมา\"\r\n}', '[\"system\"]'),
(114, 'อเมริกาโนร้อน', 'drink6.jpg', '[\r\n  { \"name\": \"เอสเปรสโซ\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำร้อน\", \"amount\": 120, \"unit\": \"มิลลิลิตร\" }\r\n]', '[\r\n  \"เติมน้ำร้อนลงในแก้วกาแฟขนาดประมาณ 4 ออนซ์ (120 มิลลิลิตร)\",\r\n  \"รินช็อตเอสเปรสโซ (30 มิลลิลิตร) ลงบนผิวน้ำร้อนช้า ๆ\",\r\n  \"ปล่อยให้ครีมม่า (ฟองกาแฟ) ลอยอยู่ด้านบน พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 11, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/cafe-menus\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ กินทั้งวัน\"\r\n}', '[\"system\"]'),
(115, 'ลาเต้ร้อน', 'drink7.jpg', '[\r\n  { \"name\": \"ช็อตเอสเปรสโซ\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"นมสด\", \"amount\": 180, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '', '[\r\n  \"เติมช็อตเอสเปรสโซ (30 มิลลิลิตร) ลงในแก้วกาแฟ\",\r\n  \"สตีมนมสดจนร้อนและได้เนื้อนมเนียนละเอียด\",\r\n  \"รินนมร้อนลงในแก้วโดยเว้นจากขอบแก้วประมาณ 1 เซนติเมตร\",\r\n  \"ตักโฟมนมลงด้านบนให้เสมอกับขอบแก้ว\",\r\n  \"ตกแต่งลวดลายลาเต้อาร์ตตามต้องการ พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 11, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/cafe-menus\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ กินทั้งวัน\"\r\n}', '[\"system\"]'),
(116, 'ชาไทยเย็น', 'drink8.jpg', '[\r\n  { \"name\": \"ผงชาไทย\", \"amount\": 1, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 50, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"ครีมเทียม\", \"amount\": 15, \"unit\": \"กรัม\" },\r\n  { \"name\": \"น้ำเปล่า\", \"amount\": 100, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ตักผงชาไทยใส่ด้ามชงกาแฟ\",\r\n  \"กดฟลัชปล่อยน้ำไหลแล้วหยุดหมักชา 20 วินาที จากนั้นกดน้ำชาออกมาประมาณ 100 มิลลิลิตร\",\r\n  \"ใส่น้ำตาลอ้อย นมข้นหวาน และครีมเทียมหรือนมข้นจืดลงในเหยือกชา คนให้เข้ากัน\",\r\n  \"เทชาไทยที่ได้ลงในแก้วที่มีน้ำแข็ง พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 11, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/thai-tea-recipe\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ พริมา\"\r\n}', '[\"system\"]'),
(117, 'ชาเขียวนมสด', 'drink9.jpg', '[\r\n  { \"name\": \"ผงชาเขียว(มัทฉะ)\", \"amount\": 6, \"unit\": \"ช้อนชา\" },\r\n  { \"name\": \"นมข้นหวาน\", \"amount\": 30, \"unit\": \"มิลลิลิตร\" },\r\n  { \"name\": \"น้ำตาลทรายขาว\", \"amount\": 0.4, \"unit\": \"ช้อนโต๊ะ\" },\r\n  { \"name\": \"นมสด\", \"amount\": 50, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  { \"name\": \"น้ำร้อนจัด\", \"amount\": 200, \"unit\": \"มิลลิลิตร\" }\r\n]\r\n', '[\r\n  \"ผสมผงชาเขียวกับน้ำร้อนจัด พักไว้ 10 นาที จากนั้นกรองเอาเฉพาะน้ำชาเขียว\",\r\n  \"เติมน้ำตาลทราย นมข้นหวาน และนมสดรสจืดลงไป คนให้ละลายเข้ากันดี\",\r\n  \"เติมน้ำแข็งลงในแก้วจนเกือบเต็ม แล้วเทน้ำชาเขียวลงไปโดยเหลือขอบไว้สำหรับนมสด\",\r\n  \"ขย่านมสดให้เกิดฟองแล้วเทราดแต่งหน้าบนชาเขียว พร้อมเสิร์ฟ\"\r\n]\r\n', 1, 11, '{\r\n  \"url\": \"https://www.wongnai.com/recipes/matcha-green-tea-recipe\",\r\n  \"facebook\": \"\",\r\n  \"youtube\": \"\",\r\n  \"note\": \"จากผู้ใช้ พริมา\"\r\n}', '[\"system\"]');
